import React from "react";
import { Dropdown } from "primereact/dropdown";
import type { IDropdownSelect } from "@lmb-it/kitsconcerto-types";
import { KitsContainer } from "../../../_compat";
import { useKitsTheme } from "../../../contexts/Theme";
import { useSelectBase } from "../hooks/useSelectBase";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";

const KitsDropdown = ({ className, ref, ...rawProps }: IDropdownSelect) => {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('DropdownSelect', rawProps, 'Select');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        id,
        rightAddon,
        leftAddon,
        errors,
        invalid,
        disabled,
        required,
        label,
        localProps,
        helperText,
        isFloatedLabel,
        withFilter,
        attached,
        inputSize,
        placeholder,
        hideError,
        virtualScroll,
        emptyFilterMessage,
        filterBy,
        loading,
        showClear,
        containerStyle,
    } = props;

    const { list, keys, onChange, selectedValue } = useSelectBase();

    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const borderColor = resolveToken('border');

    const Element = (
        <Dropdown
            emptyFilterMessage={emptyFilterMessage}
            value={selectedValue ? selectedValue.toString() : selectedValue}
            placeholder={placeholder}
            options={Array.isArray(list) ? list : []}
            disabled={disabled}
            loading={loading}
            showClear={showClear ?? (!required && selectedValue != null)}
            style={{ width: 'auto', height: attached ? '35px' : '100%', borderRadius: 0, ...(resolvedRootStyle || resolvedThemeStyle) }}
            panelStyle={{ width: 'auto' }}
            onChange={onChange}
            {...keys}
            filter={!!withFilter}
            filterBy={filterBy ?? 'label'}
            virtualScrollerOptions={virtualScroll}
            className={className ?? ''}
            pt={{
                root: {
                    style: {
                        borderRadius: 0,
                        border:'none',
                        alignItems:'center'
                    }
                },
                filterInput:{
                  style:{
                      borderRadius: 0, border:'none'
                  }
                },
                item: ({ context }: any) => context?.selected ? {
                    style: { backgroundColor: primaryColor, color: 'white' }
                } : context?.focused ? {
                    style: { backgroundColor: `color-mix(in srgb, ${primaryColor} 12%, transparent)` }
                } : undefined,
            }}
            {...(localProps ? localProps : {})}
        />
    );

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            inputSize={inputSize}
            isFloatedLabel={isFloatedLabel}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            hideError={hideError}
            errors={errors}
            helperText={helperText}
            invalid={invalid}
            label={label}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
}
export default KitsDropdown;
